INSERT INTO `project_details` (`id`, `project_header_id`, `developer_id`, `progress_date`, `status`, `progress_percent`, `description`, `created_at`, `updated_at`) VALUES
	(2, 1, 173, '2026-01-09 09:52:27', 'in_progress', 5, 'Desain UI Customer Visit', '2026-01-09 02:52:27', '2026-01-09 02:52:27'),
	(3, 1, 15, '2026-01-09 10:49:50', 'in_progress', 10, 'Fatih sudah buat desain Sales Activity di HP', '2026-01-09 03:49:50', '2026-01-09 03:49:50'),
	(5, 3, 18, '2026-01-09 14:24:20', 'in_progress', 90, 'Aplikasi telah diuji oleh tim AR dan saat ini berjalan normal. Kami masih menunggu konfirmasi dari divisi Finance untuk proses verifikasi WhatsApp Business agar mendapatkan centang biru dan nama tampil otomatis tanpa perlu disimpan.', '2026-01-09 07:24:20', '2026-01-09 07:24:20'),
	(6, 2, 21, '2026-01-06 08:00:00', 'in_progress', 5, 'Migrasi sistem Gsheet untuk ekosistem SCM\r\n- Analisis semua file terkait\r\n- Testing penggunaan formula untuk efisiensi (ternyata tidak bisa karena data yg sudah terlalu banyak)\r\n- Penetapan penggunaan Bigquery untuk tech yg digunakan (perhitungan dari scalabilitas, utilitas, performance dan integrasi ekosistem)\r\n- Rancangan untuk semua fundamental yg dibutuhkan agar terbentuknya konsistensi dalam sistem', '2026-01-09 08:09:45', '2026-01-09 08:09:45'),
	(7, 2, 21, '2026-01-07 08:00:00', 'in_progress', 15, 'Pembuatan \r\n- 7D SAQY\r\n- TS-017-GR Data\r\n\r\nBeserta Scheduling Query nya', '2026-01-09 08:16:10', '2026-01-09 08:16:10'),
	(8, 2, 21, '2026-01-08 08:00:00', 'in_progress', 30, 'Pembuatan \r\n- TS001-QO (Quantity Out) Pilar\r\n- TS003-SOH & SOPO & WO (Stock On Hand & Stock On PO & Work Order) Pilar\r\n\r\nSerta Scheduling Query', '2026-01-09 08:24:21', '2026-01-09 08:24:21'),
	(9, 1, 15, '2026-01-09 15:53:00', 'in_progress', 70, 'Senin\r\nMelakukan perbaikan UI dan UX pada halaman dashboard dengan tujuan meningkatkan kenyamanan dan kemudahan penggunaan. Tampilan dashboard telah disesuaikan, namun data yang ditampilkan masih menggunakan data dummy sebagai tahap pengembangan.\r\n\r\nSelasa – Kamis\r\nMelakukan perbaikan bug pada fitur pencarian alamat yang sebelumnya mengalami kendala. Proses ini mencakup penelusuran sumber masalah, penyesuaian logika pencarian, serta pengujian ulang hingga fitur dapat berjalan dengan normal dan stabil.\r\n\r\nJumat\r\nMelakukan pembuatan halaman untuk pengisian data customer secara manual. Pekerjaan meliputi penyusunan form input, pengaturan alur pengisian data, serta penyesuaian agar halaman dapat digunakan dengan mudah dan efisien.', '2026-01-09 09:02:04', '2026-01-09 09:02:04'),
	(10, 2, 21, '2026-01-09 08:00:00', 'in_progress', 60, 'Pembuatan data\r\n- Data MI22 (untuk kebutuhan root data item, perbaikan banyak nya data yg tidak konsisten pada tipe data Gsheet, hal ini terkendala karena Bigquery sangat Strict)\r\n- TS002-XYZ1 (50%)\r\n\r\npembuatan Scheduling\r\n\r\nPembuatan Scheduling', '2026-01-09 09:52:05', '2026-01-09 09:52:05'),
	(11, 2, 21, '2026-01-12 08:00:00', 'in_progress', 80, 'Update File Import yg dibutuhkan langsung di file SCM, melakukan beberapa Union/Join table agar data yg digunakan dapat terintegrasi tepat guna', '2026-01-12 09:46:03', '2026-01-12 09:46:03'),
	(12, 1, 15, '2026-01-13 08:15:00', 'in_progress', 75, 'Membuat fitur take picture (image belum di tambahkan ke database )', '2026-01-13 01:17:46', '2026-01-13 01:17:46'),
	(13, 1, 15, '2026-01-14 16:14:00', 'in_progress', 78, 'Membuat fitur checkIn dengan map result dan take picture', '2026-01-14 09:17:41', '2026-01-14 09:17:41'),
	(14, 2, 21, '2026-01-13 08:18:00', 'in_progress', 90, 'Pembuatan tabel untuk SCM dan register price', '2026-01-14 09:22:33', '2026-01-14 09:22:33'),
	(15, 2, 21, '2026-01-14 16:21:00', 'in_progress', 98, 'App Scripts dan juga form untuk input data Price\r\n\r\n\r\nAda beberapa kendala, dimana di gsheet untuk penyimpanan data menggunakan index, kendalanya adalah ketika data baru masuk dengan item id yg sama, maka data yg terbaru akan di indexing dengan 0 dan menambahkan index dengan item id yg sama +1, hal ini tidak memungkinkan ketika berhubungan langsung dengan ekosistem Bigquery\r\n\r\nuntuk itu perlu nya perubahan peng index an dengan metode Ascending, dimana data baru akan mendapatkan index yg makin tinggi nilai nya ketika ada item id yg sama', '2026-01-14 09:27:10', '2026-01-14 09:27:10'),
	(16, 1, 15, '2026-01-20 09:39:00', 'in_progress', 80, 'Fix bug pada plan', '2026-01-20 02:41:13', '2026-01-20 02:41:13'),
	(41, 2, 21, '2026-01-26 11:57:00', 'resolved', 100, 'Penyesuaian data done, penggunaan data yg dibutuhkan done, training untuk upload done', '2026-01-28 04:59:57', '2026-01-28 04:59:57'),
	(42, 1, 15, '2026-02-02 08:25:00', 'in_progress', 95, 'Tinggal buat backend untuk dashboard', '2026-02-02 01:28:11', '2026-02-02 01:28:11'),
	(51, 3, 18, '2026-02-06 14:25:00', 'resolved', 100, 'Selesai Membuat WA Blast', '2026-02-06 07:26:21', '2026-02-06 07:26:21'),
	(52, 1, 15, '2026-02-27 11:11:20', 'pending', 95, 'test', '2026-02-27 04:11:20', '2026-02-27 04:11:20'),
	(53, 1, 21, '2026-02-27 11:11:52', 'in_progress', 95, 'test', '2026-02-27 04:11:52', '2026-02-27 04:11:52'),
	(54, 9, 173, '2026-03-10 17:08:00', 'in_progress', 50, 'Meeting tanggal 9 Maret 2026 dan 10 Maret 20206 dengan Rizqi, Bima, Bayu, Apri, Fatih, Agam, dan Azi mencoba prompt ter-akurat untuk rejuve produk dari sisi angle dan view.', '2026-03-10 10:11:42', '2026-03-10 10:11:42');
INSERT INTO `project_headers` (`id`, `project_code`, `project_name`, `request_date`, `requestor_id`, `status`, `priority`, `progress_percent`, `description`, `notes`, `progress_date`, `start_date`, `end_date`, `actual_start_date`, `actual_end_date`, `total_pending_minutes`, `effective_end_date`, `is_late`, `created_at`, `updated_at`) VALUES
	(1, 'PRJ-001', 'Sales Activity Plan Application', '2025-11-28 09:47:00', 33, 'in_progress', 'high', 95, 'Pengembangan aplikasi mobile untuk mendukung pencatatan dan monitoring aktivitas sales, meliputi perencanaan aktivitas, tracking check-in dan check-out visitasi customer, serta pencatatan follow-up customer melalui telepon. Aplikasi ini bertujuan untuk meningkatkan visibilitas aktivitas sales, akurasi data visitasi, serta menyediakan data real-time sebagai dasar evaluasi produktivitas dan kinerja tim sales.', NULL, '2026-02-02 08:25:00', '2025-12-01 09:45:00', '2026-01-31 09:45:00', NULL, NULL, 0, '2026-01-31 09:45:00', 0, '2026-02-05 02:30:55', '2026-02-27 04:11:52'),
	(2, 'PRJ-002', 'Goto Price', '2026-01-09 02:32:00', 33, 'resolved', 'high', 100, 'Pembuatan ulang Aplikasi Update Sales Price untuk Goto E-Commerce sebagai wadah untuk membaharui Harga jual produk di platform Marketplace. Aktivitas input oleh dept. Product dan aktivitas view oleh dept. Goto E-Commerce.', NULL, '2026-01-06 08:01:00', '2026-01-06 02:33:00', '2026-01-12 02:33:00', '2026-01-06 09:58:32', '2026-01-26 11:57:00', 0, '2026-01-12 02:33:00', 1, '2026-02-05 02:34:02', '2026-02-05 02:58:32'),
	(3, 'PRJ-003', 'WA Billing Blast untuk Finance AR', '2026-01-09 02:34:00', 33, 'resolved', 'high', 100, 'Pembuatan Aplikasi WhatsApp Blast untuk mendukung sistem pengiriman penagihan secara massal melalui WhatsApp, dengan menggunakan template pesan dan data yang terstruktur serta terotomasi. Aplikasi ini dirancang untuk memudahkan tim penagihan dalam mengelompokkan invoice dan menyusun pesan penagihan yang disesuaikan untuk setiap pelanggan secara efisien dan konsisten', NULL, '2026-02-06 14:25:00', '2025-12-11 02:35:00', '2026-02-14 02:35:00', '2026-01-09 09:52:38', '2026-02-06 14:25:00', 0, '2026-02-14 02:35:00', 0, '2026-02-05 02:35:37', '2026-02-06 07:26:21'),
	(5, 'PRJ-005', 'Implementing Budgeting in Netsuite', '2026-01-12 04:23:00', 26, 'waiting', 'medium', 0, 'Mengimplementasikan Budgeting ke dalam Netsuite sampai di laporan laba rugi di Netsuite', NULL, NULL, '2026-01-12 04:29:00', '2026-02-12 04:29:00', NULL, NULL, 0, NULL, 0, '2026-02-06 04:31:10', '2026-02-06 04:31:10'),
	(8, 'PRJ-008', 'Renew Buyer Tools', '2026-03-10 10:04:00', 33, 'waiting', 'high', 0, 'Renew Buyer Tools agar performa meningkat dan data akurat.', NULL, NULL, '2026-03-11 01:00:00', '2026-03-24 10:04:00', NULL, NULL, 0, NULL, 0, '2026-03-10 10:07:28', '2026-03-10 10:07:28'),
	(9, 'PRJ-009', 'Buat Prompt Database untuk kebutuhan Designer rejuve produk di Marketplace', '2026-03-04 10:06:00', 158, 'in_progress', 'high', 50, 'Buat Prompt Database untuk digunakan Designer untuk rejuve image untuk menghasilkan total 640-an image untuk marketplace', NULL, '2026-03-10 17:08:00', '2026-03-09 01:00:00', '2026-03-12 10:06:00', '2026-03-10 17:11:42', NULL, 0, NULL, 0, '2026-03-10 10:10:02', '2026-03-10 10:11:42');
